    "name": "Sentinel Shield",
    "type": "equipment",
    "price": 510,
    "rarity": "uncommon",
    "isMagic": true,
    "image": "icons/equipment/shield/heater-steel-sword-yellow-black.webp",
    "description": "<div class=\"ddb\">\n<p>While holding this shield, you have advantage on initiative rolls and &amp;Reference[wis]{Wisdom} (&amp;Reference[prc]{Perception}) checks. The shield is emblazoned with a symbol of an eye.</p>\n</div>",
    "weight": 6,
