    "rarity": "common",
    "isMagic": false,
    "image": "https://assets.forge-vtt.com/bazaar/modules/kctg-5e/assets/images/Training%20Dummy.webp",
    "description": "<p>While quite rare and often quickly replaced by living partners, training dummies serve the purpose of training new combatants in body positions and strike techniques. Due to their fragility and tendency to break with minimal use, they are rare.</p>",
    "weight": 20,
    "folder": "Carpentry",
